mapper.update:
/*tranferMapper.updateMspRequestAgent*/ UPDATE MSP_REQUEST_AGENT SET MINOR_AGENT_NAME = CASE WHEN MINOR_AGENT_NAME IS NOT NULL THEN '이관고객' ELSE '' END , MINOR_AGENT_RRN = CASE WHEN MINOR_AGENT_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(MINOR_AGENT_RRN), 1, 7) || '******') ELSE '' END , MINOR_AGENT_TEL_FN = CASE WHEN MINOR_AGENT_TEL_FN IS NOT NULL THEN '000' ELSE '' END , MINOR_AGENT_TEL_MN = CASE WHEN MINOR_AGENT_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , MINOR_AGENT_TEL_RN = CASE WHEN MINOR_AGENT_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, JRDCL_AGENT_NAME = CASE WHEN JRDCL_AGENT_NAME IS NOT NULL THEN '이관고객' ELSE '' END , JRDCL_AGENT_RRN = CASE WHEN JRDCL_AGENT_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(JRDCL_AGENT_RRN), 1, 7) || '******') ELSE '' END , JRDCL_AGENT_TEL_FN = CASE WHEN JRDCL_AGENT_TEL_FN IS NOT NULL THEN '000' ELSE '' END , JRDCL_AGENT_TEL_MN = CASE WHEN JRDCL_AGENT_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , JRDCL_AGENT_TEL_RN = CASE WHEN JRDCL_AGENT_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, ENTRUST_REQ_NM = CASE WHEN ENTRUST_REQ_NM IS NOT NULL THEN '이관고객' ELSE '' END , ENTRUST_RES_NM = CASE WHEN ENTRUST_RES_NM IS NOT NULL THEN '이관고객' ELSE '' END , ENTRUST_RES_RRN = CASE WHEN ENTRUST_RES_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(ENTRUST_RES_RRN), 1, 7) || '******') ELSE '' END , ENTRUST_RES_TEL_FN = CASE WHEN ENTRUST_RES_TEL_FN IS NOT NULL THEN '000' ELSE '' END , ENTRUST_RES_TEL_MN = CASE WHEN ENTRUST_RES_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , ENTRUST_RES_TEL_RN = CASE WHEN ENTRUST_RES_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
WHERE REQUEST_KEY = #{requestKey}

/*tranferMapper.updateMspRequestChange*/ UPDATE MSP_REQUEST_CHANGE SET NAME_CHANGE_NM = CASE WHEN NAME_CHANGE_NM IS NOT NULL THEN '이관고객' ELSE '' END , NAME_CHANGE_TEL_FN = CASE WHEN NAME_CHANGE_TEL_FN IS NOT NULL THEN '000' ELSE '' END , NAME_CHANGE_TEL_MN = CASE WHEN NAME_CHANGE_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , NAME_CHANGE_TEL_RN = CASE WHEN NAME_CHANGE_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, NAME_CHANGE_RRN = CASE WHEN NAME_CHANGE_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(NAME_CHANGE_RRN), 1, 7) || '******') ELSE '' END
WHERE REQUEST_KEY = #{requestKey}

/*tranferMapper.updateMspRequestCstmr*/ UPDATE MSP_REQUEST_CSTMR SET CSTMR_NAME = CASE WHEN CSTMR_NAME IS NOT NULL THEN '이관고객' ELSE '' END , CSTMR_NATIVE_RRN = CASE WHEN CSTMR_NATIVE_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(CSTMR_NATIVE_RRN), 1, 7) || '******') ELSE '' END , CSTMR_FOREIGNER_PN = '' , CSTMR_FOREIGNER_RRN = CASE WHEN CSTMR_FOREIGNER_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(CSTMR_FOREIGNER_RRN), 1, 7) || '******') ELSE '' END , CSTMR_PRIVATE_CNAME = CASE WHEN CSTMR_PRIVATE_CNAME IS NOT NULL THEN '이관고객' ELSE '' END , CSTMR_JURIDICAL_CNAME = CASE WHEN CSTMR_JURIDICAL_CNAME IS NOT NULL THEN '이관고객' ELSE '' END , CSTMR_PRIVATE_NUMBER = '' , CSTMR_JURIDICAL_RRN = CASE WHEN CSTMR_JURIDICAL_RRN IS NOT NULL THEN SUBSTR(CSTMR_JURIDICAL_RRN, 1, 7) || '******' ELSE '' END , CSTMR_JURIDICAL_NUMBER = '' , CSTMR_TEL_FN = CASE WHEN CSTMR_TEL_FN IS NOT NULL THEN '000' ELSE '' END , CSTMR_TEL_MN = CASE WHEN CSTMR_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , CSTMR_TEL_RN = CASE WHEN CSTMR_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, CSTMR_MOBILE_FN = CASE WHEN CSTMR_MOBILE_FN IS NOT NULL THEN '000' ELSE '' END , CSTMR_MOBILE_MN = CASE WHEN CSTMR_MOBILE_MN IS NOT NULL THEN '0000' ELSE '' END , CSTMR_MOBILE_RN = CASE WHEN CSTMR_MOBILE_RN IS NOT NULL THEN '0000' ELSE '' END
, CSTMR_ADDR = SUBSTR(CSTMR_ADDR,1,15) , CSTMR_ADDR_DTL = ''
, CSTMR_MAIL = '' , CSTMR_RECEIVE_TEL_FN = CASE WHEN CSTMR_RECEIVE_TEL_FN IS NOT NULL THEN '000' ELSE '' END , CSTMR_RECEIVE_TEL_NM = CASE WHEN CSTMR_RECEIVE_TEL_NM IS NOT NULL THEN '0000' ELSE '' END , CSTMR_RECEIVE_TEL_RN = CASE WHEN CSTMR_RECEIVE_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, OTHERS_PAYMENT_NM = CASE WHEN OTHERS_PAYMENT_NM IS NOT NULL THEN '이관고객' ELSE '' END , OTHERS_PAYMENT_RRN = CASE WHEN OTHERS_PAYMENT_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(OTHERS_PAYMENT_RRN), 1, 7) || '******') ELSE '' END , OTHERS_PAYMENT_RNM = CASE WHEN OTHERS_PAYMENT_NM IS NOT NULL THEN '이관고객' ELSE '' END WHERE REQUEST_KEY = #{requestKey}

/*tranferMapper.updateMspRequestDlvry*/ UPDATE MSP_REQUEST_DLVRY SET DLVRY_NAME = CASE WHEN DLVRY_NAME IS NOT NULL THEN '이관고객' ELSE '' END , DLVRY_TEL_FN = CASE WHEN DLVRY_TEL_FN IS NOT NULL THEN '000' ELSE '' END , DLVRY_TEL_MN = CASE WHEN DLVRY_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , DLVRY_TEL_RN = CASE WHEN DLVRY_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
, DLVRY_MOBILE_FN = CASE WHEN DLVRY_MOBILE_FN IS NOT NULL THEN '000' ELSE '' END , DLVRY_MOBILE_MN = CASE WHEN DLVRY_MOBILE_MN IS NOT NULL THEN '0000' ELSE '' END , DLVRY_MOBILE_RN = CASE WHEN DLVRY_MOBILE_RN IS NOT NULL THEN '0000' ELSE '' END
, DLVRY_ADDR = SUBSTR(DLVRY_ADDR,1,15) , DLVRY_ADDR_DTL = '' WHERE REQUEST_KEY = #{requestKey}

/*tranferMapper.updateMspRequestDtl*/
UPDATE  MSP_REQUEST_DTL
SET     MINOR_AGENT_NAME  = CASE WHEN MINOR_AGENT_NAME IS NOT NULL THEN '이관고객' ELSE '' END
        , MINOR_AGENT_TEL = CASE WHEN MINOR_AGENT_TEL IS NOT NULL THEN '00000000000' ELSE '' END
WHERE   CONTRACT_NUM = #{contractNum}

/*tranferMapper.updateMspRequestReq*/ UPDATE MSP_REQUEST_REQ SET REQ_ACCOUNT_NAME = CASE WHEN REQ_ACCOUNT_NAME IS NOT NULL THEN '이관고객' ELSE '' END , REQ_ACCOUNT_RRN = CASE WHEN REQ_ACCOUNT_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(REQ_ACCOUNT_RRN), 1, 7) || '******') ELSE '' END , REQ_ACCOUNT_NUMBER = '' , REQ_CARD_NAME = CASE WHEN REQ_CARD_NAME IS NOT NULL THEN '이관고객' ELSE '' END , REQ_CARD_RRN = CASE WHEN REQ_CARD_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(REQ_CARD_RRN), 1, 7) || '******') ELSE '' END , REQ_CARD_NO = ''
, REQ_PAY_OTHER_TEL_FN = CASE WHEN REQ_PAY_OTHER_TEL_FN IS NOT NULL THEN '000' ELSE '' END , REQ_PAY_OTHER_TEL_MN = CASE WHEN REQ_PAY_OTHER_TEL_MN IS NOT NULL THEN '0000' ELSE '' END , REQ_PAY_OTHER_TEL_RN = CASE WHEN REQ_PAY_OTHER_TEL_RN IS NOT NULL THEN '0000' ELSE '' END
WHERE REQUEST_KEY = #{requestKey}

