/*transferMapper.getTmntCntrTransStopYn*/ SELECT CASE WHEN ( SELECT TRUNC((SYSDATE - TO_DATE(MAX(STRT_DTTM), 'YYYYMMDDHH24MISS'))*24*60) FROM CMN_BATCH_EXEC_HST WHERE STAT_CD = 'ING' AND EXEC_TYPE_CD = 'SCHE'
AND BATCH_JOB_ID = 'BATCH00100' AND TO_DATE(STRT_DTTM, 'YYYYMMDDHH24MISS') > SYSDATE - 3/24) > ETC1 THEN 'Y'
AND BATCH_JOB_ID = 'BATCH00103' AND TO_DATE(STRT_DTTM, 'YYYYMMDDHH24MISS') > SYSDATE - 1) > ETC1 THEN 'Y'
ELSE USG_YN END FROM CMN_GRP_CD_MST WHERE GRP_ID = 'DEV0003' AND CD_VAL = #{cdVal}

