/*transferMapper.getOtherUsimChgExist*/
SELECT  COUNT(1)
FROM	NMCP_FREE_USIM_REQ_MST@DL_MCP MST
	   ,NMCP_FREE_USIM_REQ_DTL@DL_MCP DTL
	   ,MSP_JUO_SUB_INFO SUB
WHERE 	MST.SEQ = DTL.SEQ
  AND   DTL.CONTRACT_NUM = SUB.CONTRACT_NUM
  AND   MST.CUSTOMER_ID = #{customerId}
  AND   DTL.CONTRACT_NUM != #{contractNum}
  AND   NVL(SUB.TRNS_YN, 'N') != 'Y'
